import{j as e}from"./index-C-Sj7oxj.js";import{C as s}from"./ComplianceModulePage-fUBd5YkM.js";import"./lenderComplianceModules-vgHajYsh.js";import"./badges-C0na7qBO.js";import"./data-adapter-C-bufghB.js";import"./arrow-left-JpkA4_R2.js";import"./arrow-right-nq0jkelf.js";import"./circle-check-CjBD-LqO.js";import"./circle-B-IC-UJd.js";import"./chevron-up-BffADvVD.js";import"./triangle-alert-DeqMl7KE.js";import"./external-link-Dz5bPWJD.js";const t=[{id:"professional-address",title:"Get a Professional Business Address",description:"Replace any residential or P.O. Box address with a verifiable commercial address.",priority:"critical",ficoImpact:20,why:"Lenders physically verify your business address. A residential address triggers home-based business flags that disqualify you from most commercial products. Virtual office addresses in commercial buildings are acceptable.",warningBox:{title:"Residential address = hard lender barrier",body:"Using your home address as your business address is one of the fastest ways to get auto-declined. Many lenders and underwriters are programmed to reject home addresses regardless of your credit score or revenue."},steps:["Register a virtual office or commercial mailbox (not a P.O. Box — lenders reject P.O. Boxes)","Update your Secretary of State filing to the new address","Update your EIN record with the IRS to match","Ensure your address is consistent on all accounts: bank, licenses, credit applications"],resources:[{name:"Regus — Virtual office addresses from $49/mo",url:"https://www.regus.com/en-us/virtual-offices?utm_source=fundready&utm_medium=referral"},{name:"Alliance Virtual Offices — from $49/mo",url:"https://www.alliancevirtualoffices.com/?utm_source=fundready&utm_medium=referral"},{name:"iPostal1 — Virtual address + mail scanning",url:"https://ipostal1.com/?utm_source=fundready&utm_medium=referral"}]},{id:"google-business-profile",title:"Claim & Verify Google Business Profile",description:"Establish a verified Google Business Profile so lenders can confirm your business exists.",priority:"high",ficoImpact:0,why:"Lenders and underwriters search Google to verify your business is real before approving. An unverified or missing Google Business Profile raises immediate red flags.",steps:["Go to business.google.com and claim your listing","Verify via postcard or phone (takes 1–2 weeks for postcard)","Ensure your business name, address, and phone number exactly match your state filing","Add your business hours, website, and a brief business description"],resources:[{name:"Google Business Profile — Free",url:"https://business.google.com"}]},{id:"nap-consistency",title:"Lock NAP Consistency Across All Platforms",description:"Synchronize your Name, Address, and Phone across every directory and business account.",priority:"high",ficoImpact:10,why:"NAP stands for Name, Address, Phone. When your business information is inconsistent across Google, Yelp, 411, your bank, and your state filing, automated lender systems interpret it as a different business — or worse, a fraudulent one.",warningBox:{title:"Inconsistent NAP is an invisible score killer",body:'Even a small difference ("St." vs "Street", or "LLC" missing) causes your NAP score to drop. Lenders pay data aggregators to verify NAP — mismatches are flagged.'},steps:["Write down your exact business name, address, and phone as filed with your Secretary of State","Search Google, Yelp, Facebook, LinkedIn, and YellowPages for any existing listings","Update each listing to match your Secretary of State filing exactly","After updating, re-search every 30 days for 90 days to confirm the correct data is propagating"]},{id:"po-box-check",title:"Eliminate P.O. Box as Primary Address",description:"Replace any P.O. Box used as a primary address with a physical commercial address.",priority:"medium",ficoImpact:0,why:"P.O. Boxes are a hard decline at most banks and SBA lenders. Unlike virtual office addresses (which are physical commercial addresses), P.O. Boxes are treated as indicators of a non-operational business.",steps:["If you currently use a P.O. Box: replace it with a virtual office or commercial mailbox immediately","P.O. Box is fine as a secondary mailing address — just not primary","Update all business registrations and financial accounts to the physical commercial address"]}];function x(){return e.jsx(s,{moduleId:"business-location",icon:"📍",tasks:t})}const i=[{id:"dedicated-business-phone",title:"Get a Dedicated Business Phone Line",description:"Obtain a business phone number registered to your entity, not your personal name.",priority:"critical",ficoImpact:15,why:"Lenders verify your phone number via 411 and directory databases. A cell phone number registered to your personal name will not appear as your business number — and that gap alone can trigger a decline.",warningBox:{title:"Personal cell = not a business phone to lenders",body:"Your personal mobile number is tied to your personal identity, not your business entity. When a lender calls 411 to verify your business phone, a missing or personal listing = automatic red flag."},steps:["Get a dedicated business phone number — VoIP services work and are lender-accepted","Register the number in your business name (not your personal name)","Use this number consistently on all business accounts, licenses, and applications","Never use a Google Voice number as your primary — it does not list in 411"],resources:[{name:"RingCentral — Business VoIP from $20/mo",url:"https://www.ringcentral.com/?utm_source=fundready&utm_medium=referral"},{name:"Nextiva — Business phone system",url:"https://www.nextiva.com/?utm_source=fundready&utm_medium=referral"},{name:"Grasshopper — Virtual business phone",url:"https://grasshopper.com/?utm_source=fundready&utm_medium=referral"}]},{id:"411-listing",title:"List Your Business in 411 & National Directories",description:"Submit your business to 411 and major national directory databases used by lender underwriting systems.",priority:"critical",ficoImpact:10,why:"Commercial lenders run an automated 411 verification check on every application. If your business does not appear in the national business directory databases (which feed 411), many lenders treat this as evidence the business does not exist.",warningBox:{title:"Not in 411 = automatic decline at many lenders",body:"This is not an optional step. 411 verification is one of the first automated checks in underwriting. It takes 4–12 weeks for new listings to propagate after you submit — start this immediately."},steps:["Submit your business to 411.com (ListYourself)","Submit to YellowPages.com and Yelp for Business (free listings)","Submit to Manta, Superpages, and Hotfrog","Ensure your business name, address, and phone match your Secretary of State filing exactly","Wait 4–12 weeks for propagation, then search '411.com [your business name]' to verify"],resources:[{name:"411.com ListYourself — Free business listing",url:"https://www.411.com/listyourbusiness"},{name:"YellowPages — Free business listing",url:"https://www.yellowpages.com/advertise"},{name:"Yext — Sync listings across 70+ directories",url:"https://www.yext.com/?utm_source=fundready&utm_medium=referral"}]},{id:"phone-nap-match",title:"Ensure Phone Matches Across All Registrations",description:"Confirm your business phone is identical on your bank, state filing, and all directory listings.",priority:"medium",ficoImpact:0,why:"If your phone number on your bank account, Secretary of State filing, and 411 listing are all different, automated systems flag it as three different businesses — or a fraudulent application.",steps:["Confirm your exact business phone number","Update your Secretary of State filing if the phone is listed there","Update your business bank account contact info","Update Google Business Profile, Yelp, and all directory listings to match","Update your website's contact page and footer"]}];function A(){return e.jsx(s,{moduleId:"phones-411",icon:"📞",tasks:i})}const a=[{id:"professional-website",title:"Build a Professional Business Website",description:"Create a domain-based business website that passes lender due diligence scrutiny.",priority:"critical",ficoImpact:15,why:"Lenders search your business online as part of due diligence. A missing website or a free website (Wix.com/yourbusiness, etc.) signals an unestablished business. Most commercial lenders require a professional domain-based web presence.",warningBox:{title:"No website or free subdomain = credibility killer",body:"Using a free subdomain (wixsite.com, wordpress.com, etc.) tells lenders you haven't invested in your business. It takes less than $20/year to own a real domain — there is no excuse for not having one."},steps:["Purchase your exact business name domain (yourbusiness.com)","Build a professional site — even a simple 3–5 page site is sufficient","Include: About, Services, Contact page with your business phone and address","Ensure your business name on the website matches your Secretary of State filing exactly","Add an SSL certificate (HTTPS) — free via most hosts, required for trust"],resources:[{name:"GoDaddy — Domains from $12/yr",url:"https://www.godaddy.com/?utm_source=fundready&utm_medium=referral"},{name:"Squarespace — Professional websites from $16/mo",url:"https://www.squarespace.com/?utm_source=fundready&utm_medium=referral"},{name:"Webflow — Professional websites from $14/mo",url:"https://webflow.com/?utm_source=fundready&utm_medium=referral"}]},{id:"domain-email",title:"Get a Domain-Based Business Email Address",description:"Replace Gmail or personal email with a professional you@yourbusiness.com address.",priority:"critical",ficoImpact:5,why:"Applying for business credit or financing with a Gmail, Yahoo, or Hotmail address signals a non-serious business to lenders and underwriters. A domain-based email (you@yourbusiness.com) is a basic credibility signal that costs under $6/month.",warningBox:{title:"Gmail on a loan application = credibility red flag",body:"This is one of the easiest and cheapest items to fix, and one of the most commonly missed. Any lender who sees Gmail or Yahoo on a business application immediately discounts your application before reading the rest."},steps:["Purchase a domain if you haven't already","Set up business email via Google Workspace ($6/user/mo) or Microsoft 365 ($6/user/mo)","Create your primary address: yourname@yourbusiness.com","Update your domain email on all business accounts: bank, IRS, Secretary of State, credit applications","Set up email forwarding from your old personal email if needed during transition"],resources:[{name:"Google Workspace — Business email from $6/mo",url:"https://workspace.google.com/?utm_source=fundready&utm_medium=referral"},{name:"Microsoft 365 Business Basic — $6/mo",url:"https://www.microsoft.com/en-us/microsoft-365/business/compare-all-plans?utm_source=fundready&utm_medium=referral"}]},{id:"website-name-match",title:"Ensure Website Matches Your Legal Business Name",description:"Verify that your website displays your legal business name consistently with your state filing.",priority:"high",ficoImpact:0,why:"Lenders cross-reference your application business name with what appears on your website. A mismatch (e.g., DBA on website vs. legal entity name on application) creates confusion that can delay or kill an approval.",steps:["Check that your website footer shows your full legal business name (e.g., 'Smith Consulting LLC')","Ensure your About page or Contact page matches the name on your state filing","If you operate under a DBA, display both: 'ABC Marketing, a division of Smith Consulting LLC'","Update your domain WHOIS record to show your business name (or use WHOIS privacy)"]}];function N(){return e.jsx(s,{moduleId:"website-email",icon:"🌐",tasks:a})}const n=[{id:"obtain-ein",title:"Obtain Your EIN from the IRS",description:"Apply for a free Employer Identification Number to separate your business identity from your personal SSN.",priority:"critical",ficoImpact:25,why:"Your EIN (Employer Identification Number) is the Social Security number of your business. Without it, you cannot open a business bank account, apply for business credit, or file business taxes separately from your personal return. Every lender requires it.",steps:["Go to IRS.gov and apply for an EIN online — it takes 10 minutes and is free","Apply in your business entity's legal name (LLC or Corp — not your personal name)","Print and save your EIN Confirmation Letter (CP 575) — lenders will ask for it","Use your EIN (not your SSN) on all business applications going forward"],resources:[{name:"IRS EIN Online Application — Free, instant",url:"https://www.irs.gov/businesses/small-businesses-self-employed/apply-for-an-employer-identification-number-ein-online"}]},{id:"business-licenses",title:"Obtain All Required Business Licenses",description:"Secure every state, county, and city business license required for your industry and location.",priority:"critical",ficoImpact:10,why:"Operating without required licenses is illegal and is an automatic decline at every lender. Underwriters verify license status with state and local databases. An expired or missing license kills a loan application even if all other factors are perfect.",warningBox:{title:"Operating without a license = automatic decline",body:"This applies even to businesses that don't 'feel like' they need one. Most states require a general business license to operate legally. Check your state, county, and city requirements separately — they are often cumulative."},steps:["Search '[your state] business license requirements' to find state-level requirements","Search '[your city/county] business license' for local requirements","Apply for all required licenses under your exact legal business name and EIN","Set calendar reminders for license renewal dates — expired licenses are treated the same as missing ones","Store all license documents in a secure folder with your formation documents"],resources:[{name:"SBA Business License & Permits Lookup — Free",url:"https://www.sba.gov/business-guide/launch-your-business/apply-licenses-permits"},{name:"LicenseSuite — Business license research by state",url:"https://www.licensesuite.com/?utm_source=fundready&utm_medium=referral"}]},{id:"professional-licenses",title:"Obtain Industry-Specific Professional Licenses",description:"Identify and obtain any professional or specialized licenses required for your industry.",priority:"high",ficoImpact:0,why:"Certain industries (healthcare, construction, real estate, legal, financial services, food service) require professional or industry-specific licenses in addition to a general business license. Operating in a licensed field without the proper credential is a felony in most states — and an instant lender decline.",steps:["Identify whether your industry requires a professional or specialized license","Apply for required professional licenses under your entity","Ensure your professional license is tied to your EIN and business entity (not just to you personally)","Store license numbers — lenders frequently ask for them on applications"]},{id:"ein-consistency",title:"Ensure EIN is Consistent Across All Registrations",description:"Audit all business accounts and update any that still use your SSN instead of your EIN.",priority:"medium",ficoImpact:0,why:"Using your SSN on some accounts and your EIN on others creates two separate credit profiles — and neither one will be strong. Mixing them also creates compliance issues that can delay loan closings.",infoBox:{title:"EIN consistency rule",body:"From the day you get your EIN, never use your SSN on a business application again. Every business account, application, and filing should use your EIN. Your SSN still appears on personal guarantees — that is different from the business application itself."},steps:["Audit your existing business accounts: bank, credit cards, and vendors","Identify any that are registered under your SSN","Contact each to update to your EIN","Going forward: always use EIN on business applications, SSN only on personal guarantee sections"]}];function E(){return e.jsx(s,{moduleId:"ein-licenses",icon:"📋",tasks:n})}const r=[{id:"open-business-checking",title:"Open a Dedicated Business Checking Account",description:"Establish a business bank account in your entity name using your EIN to build a clean financial history.",priority:"critical",ficoImpact:30,why:"Your business bank account is the most fundamental credibility signal to any lender. Every lender requires at least 3 months of business bank statements showing consistent revenue. Without a separate business account, you have no financial history that lenders can evaluate.",warningBox:{title:"Mixing personal and business funds = hard lender barrier",body:"If you run business revenue through a personal account, no traditional lender will touch you. Commingling funds also pierces the corporate veil — meaning you lose your personal liability protection. This is a non-negotiable."},steps:["Open a business checking account in your exact legal business entity name","Use your EIN (not SSN) when opening the account","Deposit all business revenue into this account going forward — no exceptions","Pay all business expenses from this account","Let the account age a minimum of 3 months before applying for business credit"],resources:[{name:"Chase Business Complete Checking — No min opening deposit",url:"https://www.chase.com/business/banking/checking?utm_source=fundready&utm_medium=referral"},{name:"Bank of America Business Advantage — Full-service business banking",url:"https://www.bankofamerica.com/smallbusiness/checking/?utm_source=fundready&utm_medium=referral"},{name:"Relay Business Banking — No fees, built for small business",url:"https://relayfi.com/?utm_source=fundready&utm_medium=referral"}]},{id:"minimum-balance",title:"Maintain a Healthy Average Daily Balance",description:"Keep your average daily balance above $2,500 to achieve a positive internal bank rating.",priority:"high",ficoImpact:10,why:"Your bank internally rates every business account on a scale of 1–9. An average daily balance below $1,000 earns you their worst rating. A Low-4 or better rating (requiring $2,500–$10,000 average daily balance) is what unlocks bank relationship products.",infoBox:{title:"Bank rating: the invisible score lenders see",body:"When you apply at your own bank, they share your internal bank rating with underwriting. Most borrowers never see this rating, but lenders use it heavily. A single NSF or sustained low balance can lock you out of your own bank's products."},steps:["Target a minimum average daily balance of $2,500 — this is the Low-4 threshold","Never let your balance drop below $1,000 — below this triggers negative bank rating","If you have irregular cash flow, maintain a buffer savings account to protect the checking balance","Work toward $10,000+ average daily balance — this unlocks the best bank rating tier"]},{id:"nsf-elimination",title:"Eliminate All NSFs and Overdrafts",description:"Prevent Non-Sufficient Funds transactions, which cause automatic loan declines at virtually every lender.",priority:"critical",ficoImpact:0,why:"A single NSF (Non-Sufficient Funds) on your business bank statements is an automatic decline at virtually every lender. Banks and underwriters scan statements specifically for NSF transactions before a human ever reviews your application.",warningBox:{title:"One NSF = automatic loan decline — no exceptions",body:"NSF fees appear on bank statements as a line item. Underwriters are trained to look for them. Even one NSF in the past 12 months will disqualify you at most traditional lenders. Zero tolerance policy."},steps:["Set up overdraft protection linked to a business savings account","Enable low balance alerts at $500, $1,000, and $2,500","If you have NSFs on recent statements: wait until they are at least 12 months old before applying","Maintain a cash buffer equal to your largest expected expense to prevent future NSFs"]},{id:"banking-history",title:"Build 3–6 Months of Clean Banking History",description:"Establish a consistent deposit pattern over at least 3 months before applying for business credit.",priority:"high",ficoImpact:0,why:"Lenders require a minimum of 3 months of business bank statements showing consistent deposits. Newer accounts are a harder sell. 6 months of clean, consistent history dramatically expands your lender options.",steps:["Do not apply for business loans until your account is at least 3 months old","Deposit consistently — even small regular deposits build pattern credibility","Keep statements clean: no NSFs, no large unexplained withdrawals, no round-number transfers that look like cash movement","After 6 months, you unlock the majority of online lenders; after 12 months, traditional banks and SBA"]}];function q(){return e.jsx(s,{moduleId:"business-banking",icon:"🏦",tasks:r})}const o=[{id:"naics-code",title:"Identify and Register Your Correct NAICS Code",description:"Verify your 6-digit NAICS code accurately reflects your primary business activity across all registrations.",priority:"critical",ficoImpact:15,why:"NAICS codes classify your industry and drive lender risk assessment. An incorrect NAICS code can flag you as high-risk, restrict your loan products, or cause an underwriter to deny you for programs you actually qualify for. It also affects which SBA programs you're eligible for.",warningBox:{title:"Wrong NAICS code = wrong risk tier",body:"If your NAICS code classifies you as a higher-risk industry than you actually are, you pay more and have fewer options. If it's wrong in the other direction, you may not qualify for industry-specific programs. Get it right."},steps:["Search the NAICS code lookup tool at census.gov/naics","Choose the most specific 6-digit code that matches your primary business activity","Verify your NAICS code matches on: Secretary of State filing, IRS EIN registration, and D&B listing","If your NAICS code triggers high-risk flags (financial services, cannabis-adjacent, etc.), consult a business advisor before applying for credit"],resources:[{name:"U.S. Census NAICS Code Lookup — Free official tool",url:"https://www.census.gov/naics/"}]},{id:"duns-number",title:"Register with Dun & Bradstreet and Get a D-U-N-S Number",description:"Establish your business identity at D&B to create a credit file at the largest business credit bureau.",priority:"critical",ficoImpact:10,why:"Dun & Bradstreet is one of the three major business credit bureaus. Your D-U-N-S number is your business's identity at D&B and is required for most government contracting, corporate supply chains, and many lender applications. Without it, you have no D&B credit file.",steps:["Go to dnb.com/get-a-duns-number and register your business for free","Ensure your business name, address, and phone match your Secretary of State filing exactly","The free D-U-N-S takes 30 business days — use this to plan ahead","Once registered, monitor your D&B file for errors and update as your business information changes"],resources:[{name:"Dun & Bradstreet — Get a free D-U-N-S Number",url:"https://www.dnb.com/duns-number/get-a-duns.html"}]},{id:"experian-equifax-biz",title:"Register with Experian Business and Equifax Business",description:"Verify your business has an active file at both Experian Business and Equifax Business credit bureaus.",priority:"high",ficoImpact:0,why:'The three major business credit bureaus are D&B, Experian Business, and Equifax Business. Lenders pull from all three. If you have no file at any one of them, that bureau returns a "no file" result — which lenders interpret as high risk.',steps:["Visit Experian Business (businesscredit.experian.com) — verify your business appears or register it","Visit Equifax Business (equifax.com/business) — same process","Ensure your business name, address, phone, and EIN are consistent at both bureaus","If you find inaccurate information at either bureau, file a dispute immediately"],resources:[{name:"Experian Business Credit — Verify or register your business",url:"https://www.experian.com/business/products/business-credit.html"},{name:"Equifax Business Credit — Verify your business",url:"https://www.equifax.com/business/business-credit/"}]},{id:"bureau-consistency",title:"Ensure Consistent Business Info Across All Three Bureaus",description:"Reconcile your business name, address, phone, and EIN across D&B, Experian, and Equifax.",priority:"medium",ficoImpact:0,why:"When your business name, address, phone, or EIN varies between D&B, Experian, and Equifax, each bureau treats them as different entities. This means your credit history is split across phantom businesses and none of your profiles is strong.",steps:["Pull your business credit reports from all three bureaus","Create a spreadsheet: exact name, address, phone, EIN, date established at each bureau","File corrections with any bureau showing inaccurate information","Monitor quarterly — data aggregators push inaccurate data to bureaus regularly"]}];function L(){return e.jsx(s,{moduleId:"agencies-naics",icon:"🔢",tasks:o})}const l=[{id:"lender-ready-business-plan",title:"Write a Lender-Ready Business Plan",description:"Create a complete business plan package that meets SBA and bank lending requirements.",priority:"critical",ficoImpact:20,why:"Every SBA loan, bank term loan, and most commercial lending programs require a business plan. Without one, you are locked out of the largest and lowest-rate capital sources. A one-page executive summary is the minimum — a full 10–15 page plan unlocks the best terms.",warningBox:{title:"No business plan = no SBA, no bank term loans",body:"SBA 7(a) loans, SBA 504, and most community bank products require a business plan as part of the application package. This is not negotiable. Online lenders don't require one, but they also charge 3–5x more interest."},steps:["Write a 1–2 page executive summary first — this is what lenders read","Document your business model: what you sell, who buys it, and how you deliver it","Include a brief competitive analysis — show you understand your market","Write your management team section: relevant experience of owners and key employees","Add financial projections: 3-year P&L, cash flow statement, and balance sheet","Include a 'Use of Funds' section explaining exactly how loan proceeds will be used"],resources:[{name:"SBA Business Plan Guide — Free official template",url:"https://www.sba.gov/business-guide/plan-your-business/write-your-business-plan"},{name:"LivePlan — Business plan software from $20/mo",url:"https://www.liveplan.com/?utm_source=fundready&utm_medium=referral"},{name:"Bplans — Free business plan examples by industry",url:"https://www.bplans.com/sample-business-plans/"}]},{id:"use-of-funds",title:"Create a Detailed Use of Funds Statement",description:"Itemize exactly how loan proceeds will be used with dollar amounts and business outcomes.",priority:"critical",ficoImpact:0,why:'The Use of Funds statement is often the deciding factor in whether a lender approves your application. Vague answers like "working capital" raise red flags. Specific, itemized uses signal a disciplined borrower.',infoBox:{title:"What lenders want to see",body:"'Equipment purchase: $50,000 — 2 CNC machines to increase production capacity by 40%' is far stronger than 'buy equipment.' Specificity = credibility. Lenders want to know exactly where their money goes and how it generates return."},steps:["List every intended use of loan proceeds with a dollar amount","Tie each use to a business outcome ('$30K for digital advertising → projected 20% revenue increase')","Keep the total exactly equal to the requested loan amount","If applying for multiple products, create a separate Use of Funds for each loan amount"]},{id:"financial-projections",title:"Build 3-Year Financial Projections",description:"Create monthly Year 1 and quarterly Year 2–3 projections showing debt service coverage.",priority:"high",ficoImpact:0,why:"Financial projections show lenders that you understand the math of your business and that you can service the debt. Projections without assumptions are worthless — lenders want to see the reasoning behind your numbers.",steps:["Build a monthly P&L projection for Year 1, quarterly for Years 2 and 3","Document your revenue assumptions: how many units, at what price, with what growth rate","Include your debt service line: the monthly payment for the requested loan","Show that your projected net income covers debt service by at least 1.25x (DSCR requirement)","Use Excel, Google Sheets, or LivePlan — format matters less than logic"]},{id:"personal-financial-statement",title:"Prepare a Personal Financial Statement",description:"Complete SBA Form 413 or equivalent for all owners with 20%+ ownership.",priority:"high",ficoImpact:0,why:"All business loans under $5M require a personal financial statement from any owner with 20%+ ownership. This is separate from the business plan but part of the same package. Missing it delays or kills the application.",steps:["List all personal assets: real estate, vehicles, investments, retirement accounts","List all personal liabilities: mortgages, auto loans, credit cards, student loans","Calculate your personal net worth: assets minus liabilities","Most lenders use SBA Form 413 — download it from sba.gov"],resources:[{name:"SBA Form 413 — Personal Financial Statement",url:"https://www.sba.gov/document/support-sba-form-413-personal-financial-statement"}]}];function D(){return e.jsx(s,{moduleId:"business-plan",icon:"📄",tasks:l})}const u=[{id:"document-assets",title:"Document All Business Assets and Collateral",description:"Create a complete asset schedule with current values for all business-owned property.",priority:"high",ficoImpact:15,why:"Secured lending (equipment loans, real estate, asset-based lines of credit) offers the lowest rates and highest amounts. To access these products, lenders need a clear picture of what collateral you can offer. Undocumented assets = undeclared collateral = higher rates.",steps:["Create an asset schedule: list every business asset with purchase date, original cost, and current market value","Include: equipment, vehicles, real estate, inventory, accounts receivable, intellectual property","Obtain current appraisals or market value estimates for high-value items","Keep purchase receipts, titles, and appraisals organized — lenders will request them","Update your asset schedule quarterly as you add or depreciate assets"]},{id:"ucc-search",title:"Search for Existing UCC Liens on Your Business",description:"Search your Secretary of State database to find all UCC filings against your business.",priority:"critical",ficoImpact:0,why:"UCC (Uniform Commercial Code) liens are legal claims on your business assets filed by creditors. If another lender has a blanket UCC lien on your business, new lenders cannot lend against those assets — effectively blocking you. Most business owners don't know these exist.",warningBox:{title:"Existing UCC liens can block you from new lending",body:"Merchant cash advance companies and some online lenders file UCC blanket liens as part of their standard process. If you've ever taken an MCA or online business loan, search for UCC filings immediately — they may be blocking you right now."},steps:["Search your Secretary of State's UCC filing database (free) — search by your business name and EIN","Search also by your personal name if you have personally guaranteed any business debt","If you find filings from lenders you no longer owe: contact them to request a UCC termination (Form UCC-3)","If you find filings from active lenders: note the collateral claimed — this limits what new lenders can take as security"],resources:[{name:"National UCC Filing Locator — state-by-state links",url:"https://www.nass.org/business-services/ucc-filings"}]},{id:"ucc-termination",title:"Terminate Expired or Paid-Off UCC Liens",description:"File UCC-3 termination statements for any liens from loans you have already repaid.",priority:"high",ficoImpact:0,why:"UCC filings don't automatically disappear when you pay off a loan. Creditors must file a UCC-3 termination — and many don't, leaving zombie liens on your record that block future lending.",steps:["For every paid-off loan: contact the former lender and request UCC-3 termination in writing","If they fail to respond within 20 days, you can file a UCC-3 termination yourself (check your state rules)","After termination filing, re-search your state's UCC database in 30 days to confirm removal","Document all terminations — save confirmation numbers and dates"]},{id:"understand-ucc-blanket-liens",title:"Understand How Blanket Liens Affect Future Borrowing",description:"Learn the difference between blanket and specific UCC liens and how to negotiate better terms.",priority:"medium",ficoImpact:0,why:"A blanket UCC lien (all assets) from one lender claims priority over all your business assets — meaning future lenders are subordinated and may decline to lend at all. Understanding this lets you negotiate better terms on new credit.",infoBox:{title:"Blanket lien vs. specific lien",body:"A specific lien covers one asset (e.g., 'equipment serial #12345'). A blanket lien covers everything you own now and in the future. MCAs and online lenders almost always file blanket liens. Traditional banks often file specific liens — which is better for you as a borrower."},steps:["When negotiating any new credit, ask whether the lender will file a blanket or specific UCC lien","Avoid blanket liens whenever possible — push for specific collateral liens","If you must accept a blanket lien, try to negotiate a first position lien carve-out for specific assets you may need for future financing"]}];function P(){return e.jsx(s,{moduleId:"assets-ucc",icon:"⚖️",tasks:u})}const c=[{id:"corp-vs-llc-credit",title:"Understand Corporate Advantages for Credit",description:"Learn when a C-Corp or S-Corp structure provides meaningful advantages over an LLC.",priority:"medium",ficoImpact:0,why:"C-Corps and S-Corps can issue stock, raise equity capital, and in some cases access credit products not available to LLCs. Understanding these advantages helps you make an informed decision about your entity structure — and whether converting makes financial sense.",infoBox:{title:"LLC vs. Corp for credit purposes",body:"For most small business credit purposes, an LLC and a Corporation are treated identically by lenders. The primary advantages of a Corp over an LLC are: (1) easier to raise investor equity, (2) ability to issue multiple classes of stock, (3) cleaner structure for eventual acquisition or IPO. For lending alone, LLC is often simpler."},steps:["Understand: for most business loans, LLC and Corp are treated the same by lenders","If you plan to raise venture or equity capital: a C-Corp (Delaware) is the standard","If you are in a highly regulated industry: consult a corporate attorney about entity choice","If you converted from LLC to Corp: ensure your EIN, bank account, and all filings are updated under the new entity"]},{id:"corporate-formalities",title:"Maintain Corporate Formalities and Records",description:"Hold annual meetings, keep minutes, and document major decisions with board resolutions.",priority:"high",ficoImpact:0,why:"Courts and lenders both look at whether you've maintained corporate formalities when evaluating liability and creditworthiness. Poor record-keeping can pierce the corporate veil — eliminating your personal liability protection and making your business's credit history worthless.",warningBox:{title:"Ignored formalities = pierced corporate veil",body:"If you skip annual meetings, don't keep minutes, or mix personal and business finances, a court can hold you personally liable for business debts. It also signals to sophisticated lenders that your entity is not truly separate."},steps:["Hold annual meetings (even solo) and document them with minutes","Keep corporate minutes in a dedicated binder or digital folder","Issue stock certificates if incorporated — even if it's just you","Pass corporate resolutions for major decisions (opening bank accounts, taking on debt, etc.)"]},{id:"stock-certificates",title:"Issue and Record Stock Certificates Properly",description:"Maintain a current cap table and properly issued stock certificates for all shareholders.",priority:"medium",ficoImpact:0,why:"Some lenders and investors require a current cap table (capitalization table) showing who owns what percentage of the corporation. Missing or improperly issued stock certificates create due diligence delays or deal killers.",steps:["Issue stock certificates to all shareholders at the time of incorporation","Record every issuance in the corporate stock ledger","Never verbally agree to equity splits without documenting them with signed certificates and board resolutions","If you plan to bring on investors or partners: consult a corporate attorney before issuing any shares"]},{id:"board-advisors",title:"Establish an Advisory Board",description:"Formalize an advisory board to signal credibility for larger loan amounts and SBA applications.",priority:"low",ficoImpact:0,why:"For lenders evaluating larger loan amounts ($250K+), a credible management team or advisory board signals that the business has expertise beyond just the founder. It's particularly important for SBA loans, bank relationships, and any equity-based financing.",steps:["Identify 2–3 experienced advisors in your industry who would lend credibility","Formalize their role with an advisory agreement (even informal is fine early on)","List your advisory board on your business plan and website","Advisors are typically compensated with equity (0.1–0.5%) or a small cash retainer for early-stage companies"]}];function U(){return e.jsx(s,{moduleId:"corp-only-facts",icon:"🏢",tasks:c})}const d=[{id:"understand-bank-rating",title:"Understand Your Internal Bank Rating",description:"Learn how your bank scores your account on a 1–9 scale and what it means for lending.",priority:"critical",ficoImpact:20,why:"Every business bank account receives an internal risk rating from your bank — a number from 1 to 9 that determines what products they'll offer you, what interest rates you qualify for, and whether your loan application even makes it past their initial screening.",infoBox:{title:"The bank rating scale: 1–9",body:`1-3: Undesirable (account may be closed, no loan products)
4: Low-4 — minimum acceptable (basic products available)
5-6: Standard (most bank products available)
7-8: Preferred (best rates, relationship banking)
9: Premium (private banking, lowest rates)`},steps:["Your bank rating is not publicly disclosed — you can estimate it based on your account behavior","Key factors: average daily balance, NSF history, account age, number of products, deposit consistency","A Low-4 rating requires: no NSFs, $2,500+ average daily balance, 6+ months account history","To improve: increase average daily balance, eliminate overdrafts, add business products (savings, credit card) at the same bank"]},{id:"average-daily-balance",title:"Build Your Average Daily Balance to $10,000+",description:"Track and grow your 90-day average daily balance to reach preferred banking status.",priority:"high",ficoImpact:0,why:"Average daily balance is the single biggest factor in your bank rating. Banks calculate it over a 30, 60, and 90-day window. Hitting $10,000 average daily balance unlocks a High-5 or better rating — which is where preferred products, better rates, and relationship lending start.",steps:["Track your current average daily balance for the last 90 days","Set a 90-day goal: $2,500 minimum → $5,000 → $10,000","Deposit a cash reserve buffer to maintain the balance baseline","If you have multiple bank accounts: consolidate to build a stronger balance at one primary bank","Avoid sweeping funds out of business checking for personal use — this destroys your ADB"]},{id:"banking-relationship",title:"Build a Relationship with Your Business Banker",description:"Schedule quarterly meetings with your banker to build the relationship that advocates for your loan.",priority:"high",ficoImpact:0,why:"Business banking is a relationship business. An account with a $50,000 average daily balance where the owner has never spoken to anyone gets a worse loan deal than the same account where the owner meets with their banker quarterly. Relationship = advocacy inside the bank.",infoBox:{title:"The banker advocacy effect",body:"When you apply for a loan at your own bank, your banker can go to bat for you in the credit committee. A banker who knows your business and likes you can often get marginal applications approved that would otherwise be declined. Invest in this relationship."},steps:["Request an in-person or video meeting with a small business banker at your primary bank","Bring: 3 months of bank statements, your business plan one-pager, your financial projections","Ask specifically: 'What does my account need to look like to qualify for a business line of credit?'","Follow up every 90 days — quarterly touchpoints build the relationship that pays off on your loan application"]},{id:"eliminate-nsf-bank-rating",title:"Zero NSFs — Protect Your Bank Rating at All Costs",description:"Set overdraft protection and balance alerts to prevent any NSF events on your account.",priority:"critical",ficoImpact:0,why:"NSFs are the fastest way to destroy a bank rating. A single NSF in a 12-month window can drop you two rating tiers — turning a preferred customer into an undesirable one. Banks share this data with credit reporting networks.",warningBox:{title:"One NSF destroys months of rating-building progress",body:"A bank rating takes 6–12 months to build. A single NSF can drop it in 24 hours. This is asymmetric — the damage is fast, the recovery is slow. Set overdraft protection and cash alerts today."},steps:["Enable overdraft protection immediately — link to a business savings or credit account","Set automated low-balance alerts at $1,000 and $2,500 via your bank's mobile app","Never let payroll, ACH payments, or large scheduled transactions run without confirmed funds","If you have recurring automatic payments: audit them monthly to ensure sufficient funds are present on payment dates"]}];function F(){return e.jsx(s,{moduleId:"bank-rating",icon:"⭐",tasks:d})}const p=[{id:"vendor-net30-accounts",title:"Open Vendor / Net-30 Trade Accounts",description:"Open at least 3 Net-30 vendor accounts that report to D&B, Experian Business, and Equifax Business.",priority:"critical",ficoImpact:15,why:"Vendor trade accounts (Net-30 terms) are the first and easiest form of business credit. They report to D&B, Experian Business, and Equifax Business — building your business credit file with zero personal credit check at most vendors.",infoBox:{title:"Starter vendors that report to business bureaus",body:"These vendors are known to report Net-30 accounts to business credit bureaus and are relatively easy to get approved for: Uline, Grainger, Quill, Summa Office Supplies, Crown Office Supplies, and Accounts. Apply, buy something small, pay in 30 days."},steps:["Open at least 3 Net-30 vendor accounts to establish your bureau files","Purchase a small amount ($50–$200) from each vendor within 30 days of opening","Pay on time — early payment is even better (Net-10 when possible)","Verify the vendor reports to at least one major business bureau before opening the account","After 60–90 days, pull your D&B, Experian Business, and Equifax Business reports to confirm the accounts are reporting"],resources:[{name:"Uline — Net-30 shipping supplies",url:"https://www.uline.com"},{name:"Grainger — Net-30 industrial supplies",url:"https://www.grainger.com"},{name:"Quill — Net-30 office supplies",url:"https://www.quill.com"}]},{id:"business-credit-card",title:"Open a Business Credit Card (Reporting to Business Bureaus)",description:"Get a business credit card that reports to business credit bureaus, not just personal bureaus.",priority:"high",ficoImpact:0,why:"A business credit card that reports to business credit bureaus builds your credit file and demonstrates revolving credit management ability — one of the key factors in commercial loan decisions.",warningBox:{title:"Not all business cards report to business bureaus",body:"Many popular business cards (including some AmEx and Chase products) only report to personal bureaus. For business credit building, you need cards that report to D&B, Experian Business, or Equifax Business. Check before applying."},steps:["Research which business cards report to business credit bureaus specifically","Apply for a card with no annual fee initially — keep utilization below 30%","Use the card for regular business expenses and pay in full monthly","After 6 months of clean history, apply for a second business card to increase available credit"],resources:[{name:"Nav — Compare business credit cards by bureau reporting",url:"https://www.nav.com/business-credit-cards/?utm_source=fundready&utm_medium=referral"}]},{id:"utilization-management",title:"Keep Business Credit Utilization Below 30%",description:"Monitor and manage revolving balances to stay under 30% utilization across all business credit.",priority:"high",ficoImpact:0,why:"Utilization (balance ÷ credit limit) is the most actionable factor in your business credit score. Business credit scoring algorithms penalize utilization above 30% heavily — keeping balances low relative to limits is the fastest way to improve your score month-over-month.",steps:["Calculate your current utilization: total balances ÷ total credit limits across all business cards","If over 30%: pay down balances immediately or request credit limit increases","Never let any single card exceed 50% utilization, even if your overall average is low","Pay balances before the statement closing date to keep reported balances lower than actual charges"]},{id:"bureau-monitoring",title:"Monitor Your Business Credit Reports Quarterly",description:"Pull and review D&B, Experian Business, and Equifax Business reports every 90 days.",priority:"medium",ficoImpact:0,why:"Business credit reports contain errors far more frequently than personal credit reports because the data aggregation process is less regulated. A single incorrect negative item can cost you tens of thousands in higher interest rates. You can only dispute what you find.",steps:["Pull your D&B, Experian Business, and Equifax Business reports every 90 days","Look for: incorrect payment history, accounts you don't recognize, incorrect business information","File disputes immediately for any errors — each bureau has an online dispute process","Keep records of all disputes and their resolution confirmation"],resources:[{name:"Nav — Free business credit monitoring",url:"https://www.nav.com/?utm_source=fundready&utm_medium=referral"},{name:"Dun & Bradstreet CreditSignal — Free D&B monitoring",url:"https://www.dnb.com/products/small-business/dnb-creditsignal.html"}]}];function $(){return e.jsx(s,{moduleId:"comparable-credit",icon:"📊",tasks:p})}const m=[{id:"understand-cd-loan",title:"Understand How a CD-Secured Business Loan Works",description:"Learn the mechanics of using a Certificate of Deposit as collateral to build business credit cheaply.",priority:"medium",ficoImpact:10,why:"A Certificate of Deposit (CD) secured business loan is one of the most powerful and underused tools for building business credit. You deposit cash into a CD, borrow against it at 80–100% of the CD value, then repay the loan while the CD earns interest. The loan reports to business credit bureaus and costs you very little net interest.",infoBox:{title:"Why the CD loan strategy works",body:"A $10,000 CD earns roughly 4–5% APY. You borrow $9,000 against it at 6–7% APR. Net cost: ~2% per year, or ~$180. In return, you get a loan that reports to D&B, Experian Business, and Equifax Business as a paid installment loan — one of the highest-value tradeline types in business credit scoring."},steps:["Understand: this is a deliberate credit-building strategy, not a necessity for the cash","You need: a business bank account at the lending bank, minimum $1,000–$5,000 to deposit into the CD","The bank holds the CD as collateral — your risk is near-zero","The loan repayment history reports to business bureaus and builds a strong installment tradeline"]},{id:"open-business-cd",title:"Open a Business CD at Your Primary Bank",description:"Deposit $2,500–$10,000 into a 12-month business CD in your entity's name.",priority:"high",ficoImpact:0,why:"The CD must be at the same bank where you will take the secured loan. Your existing bank relationship (from Module 6: Business Banking) is where you execute this — it strengthens that relationship at the same time.",steps:["Ask your business banker: 'Do you offer CD-secured business loans?'","If yes: open a business CD with $2,500–$10,000 (more CD = more loan = more impact)","Term: 12-month CDs are typical for this strategy — they balance flexibility with rate","Ensure the CD is in your business entity's name, not your personal name"]},{id:"take-cd-secured-loan",title:"Take the Secured Business Loan Against Your CD",description:"Borrow 80–90% of your CD value as a business installment loan with automatic monthly payments.",priority:"high",ficoImpact:0,why:"The loan itself is the credit-builder. Taking the CD is only step one — the loan reporting to business credit bureaus is what does the work.",steps:["Request a business installment loan for 80–90% of your CD value","Confirm with the banker that this loan WILL report to business credit bureaus (not all small banks do this)","Accept the loan funds — deposit them into your business checking account","Set up automatic monthly payments to the loan from your business checking","Never let a payment be late — even one late payment destroys the benefit of this strategy"]},{id:"verify-bureau-reporting",title:"Verify the CD Loan is Reporting to Business Bureaus",description:"Confirm the loan appears on your D&B and Experian Business reports within 60 days.",priority:"critical",ficoImpact:0,why:"Some banks do not report small business loans to all three major business bureaus. If the loan isn't reporting, you get the cost without the credit benefit. Verify before committing.",warningBox:{title:"Confirm reporting before committing to the loan",body:"Ask the bank directly: 'Does this loan report to Dun & Bradstreet, Experian Business, and Equifax Business?' If they say only one bureau, it's still worth doing. If they say none, find a different bank."},steps:["Ask before signing: which business credit bureaus does this loan report to?","After your first loan payment posts (usually 30 days): pull your D&B and Experian Business reports","Confirm the loan appears as an active installment tradeline","If the loan is not showing after 60 days: contact the bank and request a manual bureau report"]}];function Y(){return e.jsx(s,{moduleId:"cd-business-loan",icon:"💰",tasks:m})}export{L as AgenciesNAICS,P as AssetsUCC,F as BankRating,q as BusinessBanking,x as BusinessLocation,D as BusinessPlan,Y as CDBusinessLoan,$ as ComparableCredit,U as CorpOnlyFacts,E as EINLicenses,A as Phones411,N as WebsiteEmail};
